import{_ as o,o as c,c as d,a2 as t}from"./chunks/framework.DvFsUg-r.js";const h=JSON.parse('{"title":"문서 유효성 검증 — Research (Phase 0)","description":"","frontmatter":{"title":"문서 유효성 검증 — Research (Phase 0)","feature_id":"013","created":"2026-06-03 18:22 (KST)","date":"2026-06-03T00:00:00.000Z"},"headers":[],"relativePath":"specs/013-docs-validation/research.md","filePath":"specs/013-docs-validation/research.md","lastUpdated":null}'),r={name:"specs/013-docs-validation/research.md"};function s(a,e,n,l,i,g){return c(),d("div",null,[...e[0]||(e[0]=[t('<h1 id="research-문서-markdown-유효성-검증" tabindex="-1">Research: 문서(Markdown) 유효성 검증 <a class="header-anchor" href="#research-문서-markdown-유효성-검증" aria-label="Permalink to &quot;Research: 문서(Markdown) 유효성 검증&quot;">​</a></h1><p>스펙의 미해결 지점과 Technical Context 결정을 해소한 결과. 각 항목: <strong>Decision / Rationale / Alternatives</strong>.</p><h2 id="r1-구현-언어·도구-—-node-esm-의존-0" tabindex="-1">R1. 구현 언어·도구 — Node ESM, 의존 0 <a class="header-anchor" href="#r1-구현-언어·도구-—-node-esm-의존-0" aria-label="Permalink to &quot;R1. 구현 언어·도구 — Node ESM, 의존 0&quot;">​</a></h2><ul><li><strong>Decision</strong>: <code>scripts/validate-docs.mjs</code>(Node 내장 모듈만). C4 스타일 린트도 외부 의존(markdownlint 등) 없이 <strong>최소 룰셋 자체 구현</strong>. 얇은 <code>.ps1</code>/<code>.sh</code> 래퍼 <ul><li><code>blog/package.json</code> 의 <code>validate:docs</code> npm script.</li></ul></li><li><strong>Rationale</strong>: 선례(importer·sync)와 일관, 추가 런타임 0. 블로그는 이미 Node 툴체인. C4 는 경고 전용이라 정교한 린터보다 고신호 소수 룰이면 충분.</li><li><strong>Alternatives</strong>: markdownlint-cli2 dev 의존 추가 — 룰 풍부하나 의존 0 원칙·설정 관리 비용 때문에 기각. 필요해지면 후속에서 C4 만 교체 가능(경고 전용이라 저위험).</li></ul><h2 id="r2-c1-빌드-유효성-—-ci-와-동일-경로-sync-먼저" tabindex="-1">R2. C1 빌드 유효성 — CI 와 동일 경로(sync 먼저) <a class="header-anchor" href="#r2-c1-빌드-유효성-—-ci-와-동일-경로-sync-먼저" aria-label="Permalink to &quot;R2. C1 빌드 유효성 — CI 와 동일 경로(sync 먼저)&quot;">​</a></h2><ul><li><strong>Decision</strong>: C1 은 <strong><code>sync-specs</code> 를 먼저 실행한 뒤 <code>npm run build</code>(strict)</strong> 를 돌린다. 즉 CI(<code>publish-blog.yml</code>)와 동일 입력. 실패 시 stderr 의 <code>파일:라인</code> 을 추출해 차단 위반으로 보고.</li><li><strong>Rationale</strong>: feature 012 사건의 직접 원인이 &quot;로컬은 build 만, CI 는 sync+build&quot; 괴리였다. C1 이 sync 를 포함해야 스펙 문서의 렌더 오류(표 셀 토큰 등)를 로컬에서 잡는다([memory] verify-specs-sync-before-build).</li><li><strong>Alternatives</strong>: build 만 호출 — 동일 괴리 재발, 기각. VitePress API 직접 호출 — CI 와 미세 차이 위험, <code>npm run build</code> 그대로 호출이 가장 충실.</li></ul><h2 id="r3-c2-프런트매터-규칙-—-유형별-표" tabindex="-1">R3. C2 프런트매터 규칙 — 유형별 표 <a class="header-anchor" href="#r3-c2-프런트매터-규칙-—-유형별-표" aria-label="Permalink to &quot;R3. C2 프런트매터 규칙 — 유형별 표&quot;">​</a></h2><ul><li><strong>Decision</strong>: 문서 유형별로 규칙을 달리한다. 상세표는 <a href="./contracts/validation-rules">contracts/validation-rules.md</a> C2. <ul><li><strong>spec</strong>(<code>specs/*/spec.md</code>): <code>title</code>·<code>feature_id</code>·<code>status</code>·<code>created</code>·<code>date</code> 필수.</li><li><strong>spec-aux</strong>(specs 내 frontmatter 보유 기타 .md): <code>title</code>·<code>created</code>·<code>date</code> 필수.</li><li><strong>journal</strong>(<code>blog/journal/**</code>): <code>title</code>·<code>created</code>·<code>date</code> 필수, <code>date</code> 는 <strong>ISO+ 시각</strong>이며 <code>created</code> 시각과 동일, <strong>파일명 <code>YYYY-MM-DD-</code> 접두와 날짜 일치</strong>.</li><li>공통: <code>created</code> 는 <code>^\\d{4}-\\d{2}-\\d{2} \\d{2}:\\d{2} \\(KST\\)$</code>.</li><li>frontmatter 가 없는 파일(checklists 등)은 <strong>C2 스킵</strong>.</li></ul></li><li><strong>Rationale</strong>: 확인 결과 spec <code>date</code> 는 날짜만(<code>2026-06-03</code>), journal <code>date</code> 는 ISO+시각(<code>...T15:40:00+09:00</code>)으로 형식이 다르다. CLAUDE.md 규칙 1(저널은 정렬용 <code>date</code>==<code>created</code> 시각)을 그대로 반영. 생성물(llm/blog-archive/synced specs)은 C2 비대상(생성기 책임).</li><li><strong>Alternatives</strong>: 모든 .md 에 단일 규칙 — spec/journal <code>date</code> 형식 차이로 오탐, 기각.</li></ul><h2 id="r4-c3-정렬·구조-—-결정-가능한-두-검사로-한정" tabindex="-1">R4. C3 정렬·구조 — 결정 가능한 두 검사로 한정 <a class="header-anchor" href="#r4-c3-정렬·구조-—-결정-가능한-두-검사로-한정" aria-label="Permalink to &quot;R4. C3 정렬·구조 — 결정 가능한 두 검사로 한정&quot;">​</a></h2><ul><li><strong>Decision</strong>: (a) <code>blog/sidebar.specs.json</code> 의 각 그룹 <code>text</code> 선두 feature 번호가 **내림차순(최신 먼저)**인지, (b) 각 저널의 <code>created</code>/<code>date</code> 날짜부가 <strong>파일명 <code>YYYY-MM-DD-</code> 접두와 일치</strong>하는지 검증.</li><li><strong>Rationale</strong>: 사이트 목록 정렬은 대부분 자동(VitePress date 내림차순·sync 생성 사이드바)이라 사람이 깨뜨릴 여지가 적다. 결정 가능하고 회귀 가치가 있는 두 지점만 검사해 오탐을 피한다. <strong>llm 인덱스의 번호 오름차순(학습 순서 예외, feature 012)은 C3 대상이 아니다</strong> — 의도된 예외.</li><li><strong>Alternatives</strong>: 모든 인덱스 본문의 링크 순서 파싱 — 형식이 제각각이라 오탐· 취약, 기각.</li></ul><h2 id="r5-c4-스타일-—-최소-고신호-룰셋-경고-전용" tabindex="-1">R5. C4 스타일 — 최소 고신호 룰셋(경고 전용) <a class="header-anchor" href="#r5-c4-스타일-—-최소-고신호-룰셋-경고-전용" aria-label="Permalink to &quot;R5. C4 스타일 — 최소 고신호 룰셋(경고 전용)&quot;">​</a></h2><ul><li><strong>Decision</strong>: 자체 구현 룰(전부 warning, 종료 코드 무영향): 잔여 플레이스홀더(<code>TODO</code>/<code>TKTK</code>/<code>???</code>/<code>NEEDS CLARIFICATION</code>/<code>&lt;placeholder&gt;</code>), 빈 링크 <code>]()</code>, 문서 내 H1 부재 또는 2개 이상, 코드펜스(```) 백틱 라인 홀수(불균형).</li><li><strong>Rationale</strong>: 빌드를 깨진 않지만 품질·완성도를 떨어뜨리는 항목을 가볍게 가시화. 경고 전용이라 오탐이 작업을 막지 않는다(R-3).</li><li><strong>Alternatives</strong>: 풀 markdownlint 룰셋 — 노이즈·설정 부담, 의존 추가. 기각(필요시 후속).</li></ul><h2 id="r6-대상-범위-글롭-와-부작용" tabindex="-1">R6. 대상 범위(글롭)와 부작용 <a class="header-anchor" href="#r6-대상-범위-글롭-와-부작용" aria-label="Permalink to &quot;R6. 대상 범위(글롭)와 부작용&quot;">​</a></h2><ul><li><strong>Decision</strong>: <strong>C1</strong>(빌드)은 사이트 전체가 대상. <strong>C2/C3/C4</strong>(정적)는 하드 코딩된 포함/제외 글롭으로 한정 — 포함: <code>specs/**/*.md</code>, <code>blog/journal/**/*.md</code>, <code>blog/*.md</code>(루트 콘텐츠). 제외: <code>node_modules</code>, <code>blog/.vitepress/{dist,cache}</code>, <code>vendor/**</code>, 그리고 <strong>생성물</strong> <code>blog/specs/**</code>·<code>blog/llm/**</code>·<code>blog/blog-archive/**</code>. 검증기는 어떤 원본도 수정하지 않는다(C1 의 sync 가 만드는 생성물은 CI 와 동일, 예외로 명시).</li><li><strong>Rationale</strong>: 생성물의 프런트매터/정렬을 사람 규약으로 강제하면 오탐(생성기가 다른 규칙으로 만든 산출물). 사람이 쓰는 원본에 C2/C3 집중(spec Assumptions).</li><li><strong>Alternatives</strong>: 저장소 전체 .md 무차별 — 생성물·벤더 오탐, 기각.</li></ul>',14)])])}const m=o(r,[["render",s]]);export{h as __pageData,m as default};
